func HashUint64(vs ...any) uint64 {
	var o any
	if len(vs) == 1 {
		o = toHashable(vs[0])
	} else {
		elements := make([]any, len(vs))
		for i, e := range vs {
			elements[i] = toHashable(e)
		}
		o = elements
	}

	hashOpts := getHashOpts()
	defer putHashOpts(hashOpts)

	hash, err := hashstructure.Hash(o, hashOpts)
	if err != nil {
		panic(err)
	}
	return hash
}
